#include <bits/stdc++.h>
#include <limits.h>
using namespace std;

int main(){
	int n;
	cin>>n;
	int a,b;
	cin>>a>>b;
	double x=1.0*b/a;
	string r;
    for(int i=1;i<=n-1;i++){
		double d,f;
		cin>>d>>f;
		double y=1.0*f/d;
        if (y-x>0.05){
            r=r+"better\n";
        }else if (x-y>0.05) {
        	r=r+"worse\n";
		}else {
			r=r+"same\n";
		}
    }
    cout<<r<<endl;
    return 0;
}
